 23→void P_WriteAILocals(ai_local* info, FILE* fp)
 24→{
 25→	int i;
 26→
 27→	file_write_int(fp, info->player_awareness_type);
 28→	file_write_int(fp, info->retry_count);
 29→	file_write_int(fp, info->consecutive_retries);
 30→	file_write_int(fp, info->mode);
 31→	file_write_int(fp, info->previous_visibility);
 32→	file_write_int(fp, info->rapidfire_count);
 33→	file_write_int(fp, info->goal_segment);
 34→
 35→	file_write_int(fp, info->next_action_time);
 36→	file_write_int(fp, info->next_fire);
 37→	file_write_int(fp, info->next_fire2);
 38→	file_write_int(fp, info->player_awareness_time);
 39→	file_write_int(fp, info->time_player_seen);
 40→	file_write_int(fp, info->time_player_sound_attacked);
 41→	file_write_int(fp, info->next_misc_sound_time);
 42→	file_write_int(fp, info->time_since_processed);
 43→
 44→	for (i = 0; i < MAX_SUBMODELS; i++)
 45→	{
 46→		file_write_short(fp, info->goal_angles[i].p);
 47→		file_write_short(fp, info->goal_angles[i].b);
 48→		file_write_short(fp, info->goal_angles[i].h);
 49→	}
 50→	for (i = 0; i < MAX_SUBMODELS; i++)
 51→	{
 52→		file_write_short(fp, info->delta_angles[i].p);
 53→		file_write_short(fp, info->delta_angles[i].b);
 54→		file_write_short(fp, info->delta_angles[i].h);
 55→	}
 56→	for (i = 0; i < MAX_SUBMODELS; i++)
 57→		file_write_byte(fp, info->goal_state[i]);
 58→	for (i = 0; i < MAX_SUBMODELS; i++)
 59→		file_write_byte(fp, info->achieved_state[i]);
 60→}
