			ailp->next_fire = F1_0 / 2;
			if (!Buddy_allowed_to_talk && CurrentLogicVersion > LogicVer::SHAREWARE)	//	If buddy not talking, make him fire flares less often.
				ailp->next_fire += P_Rand() * 4;
		}

	}
